-- Add new columns to property_owners
ALTER TABLE property_owners ADD COLUMN IF NOT EXISTS commercialRegNo VARCHAR(30) DEFAULT NULL;
ALTER TABLE property_owners ADD COLUMN IF NOT EXISTS nationalAddress VARCHAR(255) DEFAULT NULL;

-- Add new columns to brokers
ALTER TABLE brokers ADD COLUMN IF NOT EXISTS nationalId VARCHAR(20) DEFAULT NULL;
ALTER TABLE brokers ADD COLUMN IF NOT EXISTS falLicenseNumber VARCHAR(50) DEFAULT NULL;
ALTER TABLE brokers ADD COLUMN IF NOT EXISTS falLicenseType ENUM('brokerage','property_management','marketing') DEFAULT NULL;
ALTER TABLE brokers ADD COLUMN IF NOT EXISTS falLicenseIssueDate DATE DEFAULT NULL;
ALTER TABLE brokers ADD COLUMN IF NOT EXISTS falLicenseExpiryDate DATE DEFAULT NULL;
ALTER TABLE brokers ADD COLUMN IF NOT EXISTS rating DECIMAL(3,2) DEFAULT 0;
ALTER TABLE brokers ADD COLUMN IF NOT EXISTS totalDeals INT DEFAULT 0;
ALTER TABLE brokers ADD COLUMN IF NOT EXISTS approvalRequired BOOLEAN DEFAULT TRUE;

-- Add new columns to properties
ALTER TABLE properties ADD COLUMN IF NOT EXISTS approvalStatus ENUM('pending','approved','rejected') DEFAULT 'approved';
ALTER TABLE properties ADD COLUMN IF NOT EXISTS nationalAddress VARCHAR(255) DEFAULT NULL;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS deedNumber VARCHAR(50) DEFAULT NULL;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS buildingPermitNo VARCHAR(50) DEFAULT NULL;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS maintenanceBudget DECIMAL(15,2) DEFAULT 0;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS maintenanceSpent DECIMAL(15,2) DEFAULT 0;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS vacantSince DATE DEFAULT NULL;
ALTER TABLE properties ADD COLUMN IF NOT EXISTS vacancyReason ENUM('new','eviction','maintenance','end_of_contract','other') DEFAULT NULL;

-- Add new columns to units
ALTER TABLE units ADD COLUMN IF NOT EXISTS vacantSince DATE DEFAULT NULL;
ALTER TABLE units ADD COLUMN IF NOT EXISTS vacancyReason ENUM('new','eviction','maintenance','end_of_contract','other') DEFAULT NULL;

-- Add new columns to tenants
ALTER TABLE tenants ADD COLUMN IF NOT EXISTS paymentRating INT DEFAULT 5;
ALTER TABLE tenants ADD COLUMN IF NOT EXISTS propertyRating INT DEFAULT 5;
ALTER TABLE tenants ADD COLUMN IF NOT EXISTS cooperationRating INT DEFAULT 5;
ALTER TABLE tenants ADD COLUMN IF NOT EXISTS overallRating DECIMAL(3,2) DEFAULT 5.00;
ALTER TABLE tenants ADD COLUMN IF NOT EXISTS ratingNotes TEXT DEFAULT NULL;

-- Add new columns to contracts
ALTER TABLE contracts ADD COLUMN IF NOT EXISTS renewalStatus ENUM('none','pending','sent','accepted','rejected') DEFAULT 'none';
ALTER TABLE contracts ADD COLUMN IF NOT EXISTS renewedFromId INT DEFAULT NULL;
ALTER TABLE contracts ADD COLUMN IF NOT EXISTS newRentAmount DECIMAL(15,2) DEFAULT NULL;
ALTER TABLE contracts ADD COLUMN IF NOT EXISTS alert90Sent BOOLEAN DEFAULT FALSE;
ALTER TABLE contracts ADD COLUMN IF NOT EXISTS alert60Sent BOOLEAN DEFAULT FALSE;
ALTER TABLE contracts ADD COLUMN IF NOT EXISTS alert30Sent BOOLEAN DEFAULT FALSE;

-- Add new columns to payments
ALTER TABLE payments ADD COLUMN IF NOT EXISTS receiptNumber VARCHAR(50) DEFAULT NULL;
ALTER TABLE payments ADD COLUMN IF NOT EXISTS paidAmount DECIMAL(15,2) DEFAULT NULL;
ALTER TABLE payments ADD COLUMN IF NOT EXISTS escalationLevel INT DEFAULT 0;
ALTER TABLE payments ADD COLUMN IF NOT EXISTS lastReminderSent TIMESTAMP DEFAULT NULL;
ALTER TABLE payments ADD COLUMN IF NOT EXISTS daysOverdue INT DEFAULT 0;
ALTER TABLE payments ADD COLUMN IF NOT EXISTS periodCovered VARCHAR(100) DEFAULT NULL;

-- Add new columns to maintenance_requests
ALTER TABLE maintenance_requests ADD COLUMN IF NOT EXISTS assignedPhone VARCHAR(30) DEFAULT NULL;
ALTER TABLE maintenance_requests ADD COLUMN IF NOT EXISTS estimatedCost DECIMAL(15,2) DEFAULT NULL;
ALTER TABLE maintenance_requests ADD COLUMN IF NOT EXISTS ownerApprovalRequired BOOLEAN DEFAULT FALSE;
ALTER TABLE maintenance_requests ADD COLUMN IF NOT EXISTS ownerApproved BOOLEAN DEFAULT NULL;
ALTER TABLE maintenance_requests ADD COLUMN IF NOT EXISTS scheduledDate DATE DEFAULT NULL;
ALTER TABLE maintenance_requests ADD COLUMN IF NOT EXISTS completionImages JSON DEFAULT '[]';

